## [2698. 求一个整数的惩罚数](https://leetcode.cn/problems/find-the-punishment-number-of-an-integer/)

```c++
class Solution {
public:
    bool demo(int t, int i, const string& str, int target) 
    {
        if (i >= str.size()) 
        {
            return t == target;
        }
        if (t > target) 
        {
            return false;
        }
        int m=str.size();
        for (int j = 1; j <= 4; j++) 
        {
            int k=min(j, m-i);
            t += stoi(str.substr(i, k));
            if (demo(t, i + k, str, target)) 
            {
                // cout<<target<<endl;
                return true;
            }
            t -= stoi(str.substr(i, k) );
        }
        return false;
    }
    int punishmentNumber(int n) 
    {
        int res = 0;
        for (int i = 1; i <= n; i++) 
        {
            int t1 = i * i;
            string str = to_string(t1);
            if (demo(0, 0, str, i)) 
            {
                res += i * i;
            }
        }
        return res;
    }
};
```

## [491. 递增子序列](https://leetcode.cn/problems/non-decreasing-subsequences/)

[回溯参考](https://programmercarl.com/0491.%E9%80%92%E5%A2%9E%E5%AD%90%E5%BA%8F%E5%88%97.html#思路)

```c++
class Solution {
public:
    vector<vector<int>>res;
    vector<int>path;

    void dfs(vector<int>&nums,int sindex)
    {
        if(path.size() >= 2)
            res.push_back(path);
        if(sindex>=nums.size())return;
        unordered_map<int,int>used;
        for(int i=sindex;i<nums.size();i++)
        {
            int x=nums[i];
            if((!path.empty()&&nums[i]<path.back())||used[x]==1)continue;
            path.push_back(nums[i]);
            used[x]=1;
            dfs(nums,i+1);
            path.pop_back();
            // used[x]=0;
        }
    }
    vector<vector<int>> findSubsequences(vector<int>& nums) {
        res.clear();
        path.clear();
        dfs(nums, 0);
        return res;

    }
};
```

二进制优化（官解）

```c++
class Solution {
public:
    vector<int> temp;
    vector<vector<int>> ans;
    unordered_set<int> s;
    int n;

    void findSubsequences(int mask, vector<int>& nums) 
    {
        temp.clear();
        for (int i = 0; i < n; ++i) 
        {
            if (mask & 1) 
            {
                temp.push_back(nums[i]);
            }
            mask >>= 1;
        }
    }

    bool check() {
        for (int i = 1; i < temp.size(); ++i) {
            if (temp[i] < temp[i - 1]) {
                return false;
            }
        }
        return temp.size() >= 2;
    }

    int getHash(int base, int mod) {
        int hashValue = 0;
        for (const auto &x: temp) {
            hashValue = 1LL * hashValue * base % mod + (x + 101);
            hashValue %= mod;
        }
        return hashValue;
    }

    vector<vector<int>> findSubsequences(vector<int>& nums) {
        n = nums.size();
        for (int i = 0; i < (1 << n); ++i) {
            findSubsequences(i, nums);
            int hashValue = getHash(263, int(1E9) + 7);
            if (check() && s.find(hashValue) == s.end()) {
                ans.push_back(temp);
                s.insert(hashValue);
            }
        }
        // 将set中的数据复制到vector中
        //vector<vector<int>> result(res.begin(), res.end());
        // copy(res.begin(), res.end(), result.begin());
        return ans;
    }
};
```



## [332. 重新安排行程](https://leetcode.cn/problems/reconstruct-itinerary/)

```c++
#define debug(a) cout<<#a<<"="<<a<<endl
class Solution {
public:
    vector<string>res;
    unordered_map<string,map<string,int >>umap;
    int dfs(int m,string s)
    {
        if(res.size()==m+1)
        {
            return 1;
        }
        for(auto& x:umap[s])
        {
            if(x.second>0)
            {
                res.push_back(x.first);
                // debug(x.first);
                x.second--;
                // debug(x.second);
                // cout<<endl;
                if(dfs(m,x.first))return 1;
                x.second++;
                res.pop_back();
            }

        }
        return 0;
    }
    vector<string> findItinerary(vector<vector<string>>& tickets) 
    {

        for(auto x:tickets)
        {
            umap[x[0]][x[1]]++;
        }
        res.push_back("JFK");
        dfs(tickets.size(),"JFK");
        return res;
    }
};
```

