#define ll long long

using namespace std;
typedef pair<int,int> pii;
bool check(int x, int n, int m, int k, vector<int>& time, vector<int>& source) 
{
    int need = 0;
    for (int i = 0; i < n; i++) 
	{
        if (time[i] < x) continue;
        need += (time[i] - x) * source[i];
    }
    return need <= m;
}

int main() 
{
    int n, m, k;
    cin >> n >> m >> k;

    vector<int> time(n), source(n);
    for (int i = 0; i < n; i++) 
	{
        cin >> time[i] >> source[i];
    }
    int left = k-1, right = *max_element(time.begin(), time.end())+1;
    int ans = k;
    while (left +1 < right) 
	{
        int mid = (left + right) / 2;
        if (check(mid, n, m, k, time, source)) 
		{
            ans = mid;
            right = mid;
        } 
		else 
		{
            left = mid ;
        }
    }
    cout << ans << endl;
    return 0;
}
