```c++
int dir[4][2]={{0,-1},{-1,0},{0,1},{1,0}};
#define debug(a) cout<<#a<<"="<<a<<endl
class Solution {
public:
    int dfs(vector<vector<char>>& board, string word, int u,int x,int y,vector<vector<int> >& dp)
    {
        int dx=0,dy=0;
        int m=board.size();
        int n=board[0].size();
        if(board[x][y]!=word[u])
        {
            return false;
        }
        if(u==word.size()-1)
        {
            return true;
        }
		if(x>=m||y>=n||x<0||y<0)
		{
			return false;
		}
        // if(u==word.size()-1&&board[x][y]==word[u])return true;//防止只有一个格子
        for(int i=0;i<4;i++)
        {
            dx=x+dir[i][0];
            dy=y+dir[i][1];

            if(dx>=0&&dx<m&&dy>=0&&dy<n&&!dp[dx][dy]&&board[dx][dy]==word[u+1])
            {
                dp[dx][dy]=1;
                if(dfs(board,word,u+1,dx,dy,dp))return true;
                dp[dx][dy]=0;
            }
        }
        return false;
    }

    bool exist(vector<vector<char>>& board, string word) {
        int m=board.size();
        int n=board[0].size();
        vector<vector<int>> dp(m,vector<int>(n,0));
        for(int i=0;i<m;i++)
        {
            for(int j=0;j<n;j++)
            {
                dp[i][j]=1;
                if(dfs(board,word,0,i,j,dp))
                    return true;
                dp[i][j]=0;
            }
        }
        return false;
    }
};
