## [131. 分割回文串](https://leetcode.cn/problems/palindrome-partitioning/)（可纯dfs or dp优化）

### 纯dfs

sindex作为分割线
s.substr(sindex,i-sindex+1) 放入路径
i+1为下次的分割线

```c++
class Solution {
public:
    vector<vector<string>>res;
    vector<string>path;
    int isp(string s, int l,int r)
    {
        while(l<r)
        {
            if(s[l]!=s[r])
            {
                return 0;
            }
            l++;
            r--;
        }
        return true;
    }
    void dfs(string s,int sindex)
    {

        int n=s.size();
        if(sindex>=n)
        {
            res.push_back(path);
            return ;
        }
        for(int i=sindex;i<n;i++)
        {
            if(isp(s,sindex,i))
            {
                path.push_back(s.substr(sindex,i-sindex+1));
                dfs(s,i+1);
                path.pop_back();
            }
        }
    }
    vector<vector<string>> partition(string s) {
        dfs(s,0);
        return res;
    }
};
```

