### 一些string api

```c++
class Solution {
public:
    vector<string>res;

    int isvalid(string s, int l, int r)
    {
        // 遇到非数字字符不合法,0要特殊处理
        string str=s.substr(l, r-l+1);
        if(r<l)return 0;
        if(s[l]=='0'&&l!=r)return 0;
        for(auto num:str)
        {
            if(num<'0'||num>'9')return 0;
        }
        int num=stoi(str);
        if(num>255)return 0;
        return 1;
    }
    void dfs(string s,int sindex,int point)
    {

        int n=s.size();
        if(point==3)
        {
            if(isvalid(s,sindex,n-1))
            {
                res.push_back(s);
            }
            return;
        }
        for(int i=sindex;i<n;i++)
        {
            if(isvalid(s,sindex,i))
            {
               s.insert(s.begin()+i+1,'.');
               point++;
               dfs(s,i+2,point);
               s.erase(s.begin()+i+1);
               point--;
            }
            else break;//注意结束
        }
    }
    vector<string> restoreIpAddresses(string s) {
        if(s.size()>12||s.size()<4)return res;
        dfs(s,0,0);
        return res;
    }
};
