## [306. 累加数](https://leetcode.cn/problems/additive-number/)

### dfs+高精度

```c++
class Solution {
public:
    vector<vector<int>>list;
    //高精度+
    int check(vector<int>&a,vector<int>&b,vector<int>&c)
    {
        vector<int>sum;
        int carry=0;
        for(int i=0;i<a.size()||i<b.size();i++)
        {
            if(i<a.size())carry+=a[i];
            if(i<b.size())carry+=b[i];
            sum.push_back(carry%10);
            carry/=10;
        }
        if(carry)sum.push_back(1);
        if(sum.size()!=c.size())
        {
            return 0;
        }
        for(int i=0;i<sum.size();i++)
        {
            if(sum[i]!=c[i])return 0;
        }
        return 1;
    }
    int dfs(int sindex,string num)
    {
        if(sindex>=num.size())
        {
            if(list.size()>=3)
            {
                return 1;
            }
            return 0;
        }
        //特殊处理0，只能有一个划分
        int n=num.size();
        if(num[sindex]=='0')
        {
            n=sindex+1;
        }
        vector<int >cur;
        for(int i=sindex;i<n;i++)
        {
            cur.insert(cur.begin(),num[i]-'0');//高精度是倒着算的
            if(list.size()<2||check(list[list.size()-1],list[list.size()-2],cur))
            {
                list.push_back(cur);
                if(dfs(i+1,num))return 1;
                list.pop_back();
            }
        }
        return 0;
    }
    bool isAdditiveNumber(string num) {
        return dfs(0,num);
    }
};
