### *[166. 数独](https://www.acwing.com/problem/content/description/168/)*

思路
数独一看就可以暴搜，但一看就会超时，所以考虑剪枝。

优化搜索顺序 ✔ ✔
可以优先搜索位置上能填的数最少的方格

排除等效冗余 ✖ ✖
因为整棵搜索树都会搜到，所以不能排除等效冗余
可行性剪枝 ✔ ✔
这一步可以放在枚举能放的位置上进行优化
由于每一行每一列每一个宫格都不能重复，所以我们可以用位运算优化枚举数的过程
最优化剪枝 ✖ ✖
这里我们无需考虑答案最小，只需考虑是否有解

改进
优化搜索顺序，每次优先搜索可选放入数字最少的空白格子，这样它下面搜索时的分支就会少
假设当前搜索到坐标为（x，y）的这个格子

1. 先解释一下几个数组的含义
   row【i】表示第i行能放的数有哪些（1-9），是二进制表示的，9个位置上，1代表这个数能放，0代表不能放
   col【j】表示第j行能放的数有哪些（1-9），二进制表示同上
   cell【i】【j】----这里把坐标看成是3*3的，（i，j）就指向了一个唯一的小型九宫格，也是二进制表示这个小型九宫格里能放的数有哪些
   这样我们在（x，y）这个位置上放的数就是满足行，列，小型九宫格都能放的数，取交集
   row[x]&col[y]&cell[x/3][ y/3 \]三者取交集—(x/3,y/3)是小型九宫格的位置

想到位运算优化，三个二进制数进行与运算，最后得到的二进制数中为1的位置，代表这个数能放进（x，y）这个空格子里

2. 另一个位运算优化：lowbit（）
   lowbit()可以用来计算一个二进制数里面有多少个1
   lowbit举个例子：lowbit（x） x=10001000（二进制） 会返回1000（二进制）
   因为会返回1000，而不会返回我们想要直到的1在第几位，
   所以我们有额外开了数组map【】 1000->8->log2 8就是3,这样1000就会返回map【1000】=3

   map【100】=2 

3. 另外我们还需要看一下最后三者交集的二进制数结果里有多少个1，根据1的数目选择数目较少的先进行搜索，达到优化搜索顺序剪枝的目的：
   用ones【i】记录二进制数i里面有多少个1 (i属于【0,2的9次方-1】)

[](https://www.acwing.com/solution/content/56364/)

```c++
#include<bits/stdc++.h>
#define debug(a) cout<<#a<<"="<<a<<endl
#define ll long long
const int N=9;

using namespace std;
typedef pair<int,int> pii;
int  mapp[1<<N],ones[1<<N];
int row[N],col[N],ma[3][3];
string str;
inline void init()
{
	for(int i=0;i<9;i++)
	{
		row[i]=col[i]=(1<<N)-1;
	}

	for(int i=0;i<3;i++)
	{
		for(int j=0;j<3;j++)
		{
			ma[i][j]=(1<<N)-1;
		}
	}
}
inline int lowbit(int x)
{
	return x&-x;
}
inline int get(int x,int y)
{
	return row[x]&col[y]&ma[x/3][y/3];
}
int dfs(int cnt)
{
	if(!cnt)return 1;
	int minv=10,x=0,y=0;
	for(int i=0;i<9;i++)
	{
		for(int j=0;j<9;j++)
		{
			if(str[i*9+j]=='.')
			{
				int t=ones[get(i,j)];
				if(t<minv)
				{
					minv=t;
					x=i;
					y=j;
				}
			}

		}
	}
	for(int i=get(x,y);i;i-=lowbit(i))
	{
		int t=mapp[lowbit(i)];
		row[x]-=(1<<t);
		col[y]-=(1<<t);
		ma[x/3][y/3]-=1<<t;
		str[x*9+y]='1'+t;
		if(dfs(cnt-1))return 1;
		row[x]+=(1<<t);
		col[y]+=(1<<t);
		ma[x/3][y/3]+=1<<t;
		str[x*9+y]='.';
	}
	return 0;
}
int main() 
{
	for(int i=0;i<9;i++)
	{
		mapp[1<<i]=i;
	}
	for(int i=0;i<1<<N;i++)
	{
		int s=0;
		for(int j=i;j;j-=lowbit(j))s++;
		ones[i]=s;
	}
    while(cin>>str)
    {
    	if(str=="end")break;
    	init();
    	int cnt=0;
    	for(int i=0,k=0;i<9;i++)
    	{
    		for(int j=0;j<9;j++,k++)
    		{
    			if(str[k]!='.')
    			{
    				int t=str[k]-'1';
    				row[i]-=1<<t;
    				col[j]-=1<<t;
    				ma[i/3][j/3]-=1<<t;
				}
				else
				{
					cnt++;
				}
			}
		}
		dfs(cnt);
		cout<<str<<endl;
	}
    return 0;
}
```

