using namespace std;
const int N=1010;
int len,sum,n,st[N],w[N];
bool cmp(int a, int b) 
{
    return a > b;
}
int dfs(int u,int s,int start)
{
	if(u*len==sum)return 1;
	if(s==len)return dfs(u+1,0,0);//易错
	for(int i=start;i<n;i++)
	{
		if(!st[i]&&s+w[i]<=len)
		{
			st[i]=1;
			if(dfs(u,s+w[i],i+1))return 1;
			st[i]=0;
			if(!s||s+w[i]==len)return 0;
			int j=i;
			while(j<n&&w[j]==w[i])j++;
			i=j-1;
		}
	 } 
	 return 0;
}
