{
	while(cin>>n&&n)
	{
		memset(st,0,sizeof(st));
		sum=0,len=1;
		for(int i=0;i<n;i++)
		{
			cin>>w[i];
			sum+=w[i];
		}
		sort(w,w+n,cmp);
		while(1)
		{
			if(sum%len==0&&dfs(0,0,0))
			{
				cout<<len<<endl;
