typedef long long LL;
const int maxn=1010,N=31;
//char g[maxn][maxn];
int n;
int q[N],w[5][N];
int f()
{
	int res=0;
	for(int i=0;i+1<n;i++)
	{
		if(q[i+1]!=q[i]+1)
		{
			res++;
		}
	}
	return (res+2)/3;

}
bool check()
{
	for(int i=0;i<n;i++)
	{
		if(q[i]!=i+1)
			return false;
	}
	return true;
}
int dfs(int dep,int maxdep)
{
	if(dep+f()>maxdep)return 0;
	if(check())return 1;
	for(int l=0;l<n;l++)
	{
		for(int r=l;r<n;r++)
		{
			for(int k=r+1;k<n;k++)
			{
				memcpy(w[dep],q,sizeof(q));
				int x=0,y=0;
				for(x=r+1,y=l;x<=k;x++,y++)q[y]=w[dep][x];
				for(x=l;x<=r;x++,y++)q[y]=w[dep][x];
				if(dfs(dep+1,maxdep))return 1;
				memcpy(q,w[dep],sizeof(q));
			}

		}
	}
	return 0;
}
