int path[100];

int sum[4];
int f()
{
	memset(sum,0,sizeof(sum));
	for(int i=0;i<8;i++)
	{
		sum[q[center[i]]]++;
	}
	int s=0;
	for(int i=1;i<=3;i++)
	{
		s = max(s, sum[i]);
	}
	return 8-s;

}
bool check()
{
    for (int i = 1; i < 8; i ++ )
        if (q[center[i]] != q[center[0]])
            return false;
    return true;
}
void oper(int x)
{
	int t=q[op[x][0]];
	for(int i=0;i<6;i++)q[op[x][i]]=q[op[x][i+1]];

	q[op[x][6]] = t;
}
int dfs(int dep,int maxdep,int last)
{
	if(dep+f()>maxdep)return 0;
	if(!f())return 1;
	for(int i=0;i<8;i++)
	{
		if(opposite[i]==last)continue;
		oper(i);
		path[dep]=i;
		if(dfs(dep+1,maxdep,i))return 1;
		oper(opposite[i]);
	}
	return 0;
}
int main()
{
