## [LCR 028. 扁平化多级双向链表](https://leetcode.cn/problems/Qv1Da2/)

https://leetcode.cn/problems/flatten-a-multilevel-doubly-linked-list/solutions/1014046/gong-shui-san-xie-yi-ti-shuang-jie-di-gu-9wfz

### 迭代

```c++
/*
// Definition for a Node.
class Node {
public:
    int val;
    Node* prev;
    Node* next;
    Node* child;
};
*/

class Solution {
public:

    Node* flatten(Node* head) {
        Node* dummy = new Node(0);
        dummy->next = head;
        while(head)
        {
            if(head->child)
            {
               Node* tmp=head->next;
               Node* childStart=head->child ;
               head->next=childStart;
               childStart->prev=head;
               head->child=nullptr;
               Node* last=head;
               while(last->next)last=last->next; 
               last->next=tmp;
               if(tmp)tmp->prev=last;
            }
            head=head->next;
        }

        return dummy->next;
    }
};
```

### 递归

```c++
/*
// Definition for a Node.
class Node {
public:
    int val;
    Node* prev;
    Node* next;
    Node* child;
};
*/

class Solution {
public:
    Node* dfs(Node* head)
    {

        Node* last=head;
        while(head)
        {
            if(!head->child)
            {
                last=head;
                head=head->next;

            }
            else
            {
                Node* rear=head->next;
                Node* childStart=head->child;
                Node* childEnd=dfs(head->child);
                head->next=childStart;
                childStart->prev=head;
                head->child=nullptr;//记得消除child
                childEnd->next=rear;

                if(rear)//rear可能是空
                {
                    rear->prev=childEnd;
                }
                last=childEnd;
                head=rear;
            }
        }
        return last;
    }
    Node* flatten(Node* head) {
        dfs(head);
        return head;
    }
};
```

