        int p=0;
        for(int i=0;i<word.size();i++)
        {
            int u=word[i]-'a';
            if(!son[p][u])son[p][u]=++idx;
            p=son[p][u];
        }
        cnt[p]++;
    }

    bool search(string word) {
       queue<PII>q;
       q.push({0,0});
       for(int i=0;i<word.size();i++)
       {
            while(q.size()&&q.front().second == i)
            {
                auto it=q.front();
                q.pop();
                if(word[i]=='.')
                {
                    for(int j=0;j<26;j++)
                    {
                        if(son[it.first][j])
                        {
                            q.push({son[it.first][j],i+1});
                        }
                    }
                }
                else
                {
                    int u=word[i]-'a';
                    if(son[it.first][u])
                    {
                        q.push({son[it.first][u],i+1});
                    }
                }
            }

       }
       while(q.size())
        {
            auto it=q.front();
            q.pop();
            if(cnt[it.first])return true;
        }
         return false;
    }

};

