```c++

const int N = 500086;
class Trie {
private:

public:
    Trie* son[26];
    pair<int,int>cnt;
    Trie() {

        for(int i=0;i<26;i++)son[i]=nullptr;
    }
    //c++安全性
    ~Trie()
    {
        for(int i = 0; i < 26 ; i++)
        {
            if(son[i] != nullptr) delete son[i];
        }
    }    
    void insert(string word,int id) 
    {
        Trie* root=this;
        if(root->cnt.first==0||root->cnt.first > word.size())root->cnt = {word.size(), id};
        for(int i=word.size()-1;i>=0;i--)
        {
            int u=word[i]-'a';
            if(!root->son[u])root->son[u]= new Trie();
            root=root->son[u];
            if(root->cnt.first==0||root->cnt.first > word.size())root->cnt=make_pair(word.size(), id);
        }

    }
    void search(string word, vector<int>&ans) 
    {
        Trie* root=this;
        for(int i=word.size()-1;i>=0;i--)
        {
            int u=word[i]-'a';
            if(!root->son[u])break;
            root=root->son[u];
        }
        ans.push_back(root->cnt.second);
    } 
};
class Solution {
public:
    vector<int>ans;

    // pair<int,int>cnt[N];

    vector<int> stringIndices(vector<string>& wordsContainer, vector<string>& wordsQuery) {
        Trie* root=new Trie();
        int lenn=wordsContainer.size();
        for(int i=0;i<lenn;i++)
        {
            root->insert(wordsContainer[i],i);
        }
        for(auto str:wordsQuery)
        {
            root->search(str,ans);
        }
        return ans;
    }
};
